class Solution:
    def countVowelPermutation(self, n: int) -> int:
        MOD = 10**9 + 7
        dp = {'a': 1, 'e': 1, 'i': 1, 'o': 1, 'u': 1}
        transitions = {
            'a': ['e'],
            'e': ['a', 'i'],
            'i': ['a', 'e', 'o', 'u'],
            'o': ['i', 'u'],
            'u': ['a']
        }

        for _ in range(n - 1):
            next_dp = {'a': 0, 'e': 0, 'i': 0, 'o': 0, 'u': 0}
            for vowel in dp:
                for next_vowel in transitions[vowel]:
                    next_dp[next_vowel] = (next_dp[next_vowel] + dp[vowel]) % MOD
            dp = next_dp

        return sum(dp.values()) % MOD
```
